const item = $input.first().json;

function cleanText(value, fallback = '') {
  if (value === undefined || value === null) return fallback;
  return String(value).trim();
}

function normalizeKey(key) {
  return String(key || '')
    .toLowerCase()
    .replace(/["'’‘“”]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function pick(keys, fallback = '') {
  // Exact match first
  for (const key of keys) {
    const value = item[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return cleanText(value);
    }
  }

  // Fuzzy match second for messy Google Form headers
  const wanted = keys.map(normalizeKey);
  for (const [realKey, value] of Object.entries(item)) {
    if (value === undefined || value === null || String(value).trim() === '') continue;
    const normalizedRealKey = normalizeKey(realKey);
    for (const target of wanted) {
      if (normalizedRealKey === target || normalizedRealKey.includes(target) || target.includes(normalizedRealKey)) {
        return cleanText(value);
      }
    }
  }

  return fallback;
}

function escapeHtml(value) {
  return cleanText(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function normalizePhone(phone, country) {
  let p = cleanText(phone).replace(/\D/g, '');
  const c = cleanText(country).toLowerCase();

  if (!p) return '';

  // India default if 10 digit number or country says India
  if (p.length === 10 && (c.includes('india') || c.includes('in') || c === '')) {
    return '91' + p;
  }

  if (p.startsWith('0') && p.length === 11 && (c.includes('india') || c.includes('in') || c === '')) {
    return '91' + p.slice(1);
  }

  return p;
}

function extractMaxNumber(text) {
  const nums = cleanText(text).match(/\d+(?:\.\d+)?/g) || [];
  if (!nums.length) return 0;
  return Math.max(...nums.map(Number));
}

function addDays(days) {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

